using System;
using System.Threading;
using System.Threading.Tasks;

/// <summary>
/// Executes work with a timeout using cooperative cancellation.
/// Replaces the .NET Framework pattern of Thread.Abort / ThreadAbortException / ResetAbort,
/// which throws PlatformNotSupportedException in .NET 6+.
/// </summary>
public class TimedExecutor
{
    /// <summary>
    /// Runs <paramref name="work"/> on a background thread and throws
    /// <see cref="TimeoutException"/> if it does not complete within
    /// <paramref name="timeout"/>.
    /// </summary>
    /// <remarks>
    /// The work delegate receives a <see cref="CancellationToken"/> and MUST
    /// check it periodically (e.g., token.ThrowIfCancellationRequested()) for
    /// cancellation to be effective. Without cooperative checks, the work
    /// continues running in the background after timeout — unlike Thread.Abort,
    /// there is no way to forcibly terminate a managed thread in modern .NET.
    /// </remarks>
    public T ExecuteWithTimeout<T>(Func<CancellationToken, T> work, TimeSpan timeout)
    {
        using var cts = new CancellationTokenSource(timeout);
        var token = cts.Token;

        var task = Task.Run(() => work(token), token);

        try
        {
            // Block the caller until the task completes or the timeout fires.
            // Task.WaitAsync throws OperationCanceledException when the token
            // is cancelled (i.e., the timeout expired).
            task.WaitAsync(token).GetAwaiter().GetResult();
        }
        catch (OperationCanceledException) when (token.IsCancellationRequested)
        {
            throw new TimeoutException(
                $"Operation exceeded {timeout.TotalSeconds}s timeout");
        }

        // Unwrap AggregateException to surface the original exception,
        // matching the original behavior.
        if (task.IsFaulted)
            throw new AggregateException(task.Exception!.InnerExceptions);

        return task.Result;
    }

    // ── Overload for callers that don't need cancellation-aware work ──
    // WARNING: Without cooperative cancellation the work keeps running after
    // timeout — it is just abandoned. Prefer the CancellationToken overload.
    public T ExecuteWithTimeout<T>(Func<T> work, TimeSpan timeout)
    {
        return ExecuteWithTimeout(token =>
        {
            // No cancellation cooperation — the work cannot be stopped.
            return work();
        }, timeout);
    }
}

